/* MF-QA-FIX-v1 */
.mfp.mfp-project-intake-onboarding{--mf-primary:#0bb39b;--mf-accent:#0bb39b;--mf-primary-hover:#079a85;--mf-primary-light:#e2f7f2;--primary:#0bb39b;}
.mfp.mfp-project-intake-onboarding .mfp-header h1,.mfp.mfp-project-intake-onboarding .mfp-header .mfp-form-title,.mfp.mfp-project-intake-onboarding .mfp-header .mfp-eyebrow,.mfp.mfp-project-intake-onboarding .mfp-header .mfp-form-subtitle{color:#fff!important;}
/* END-MF-QA-FIX */
/* ============================================================
   MegaForm Premium Template — Project Intake & Onboarding
   Scope: .mfp.mfp-project-intake-onboarding
   All colours use --mf-* variables; hard-coded values are
   fallbacks only.
   ============================================================ */

/* ---------- Reset / Box model ---------- */
.mfp.mfp-project-intake-onboarding *,
.mfp.mfp-project-intake-onboarding *::before,
.mfp.mfp-project-intake-onboarding *::after {
  box-sizing: border-box;
}

/* ---------- Wrapper ---------- */
.mfp.mfp-project-intake-onboarding {
  font-family: inherit;
  color: var(--mf-text, #1a1a2e);
  background: var(--mf-bg, #f8fafc);
  border-radius: var(--mf-radius, 12px);
  max-width: 860px;
  width: 100%;
  margin: 0 auto;
  overflow: hidden;
  box-shadow: var(--mf-shadow, 0 8px 40px rgba(0,0,0,0.10));
}

/* ---------- Header ---------- */
.mfp.mfp-project-intake-onboarding .mfp-header {
  background: var(--mf-primary, #0bb39b);
  padding: 40px 48px 32px;
  color: #fff;
}
.mfp.mfp-project-intake-onboarding .mfp-eyebrow {
  display: inline-block;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  background: rgba(255,255,255,0.18);
  color: #fff;
  border-radius: 99px;
  padding: 3px 12px;
  margin-bottom: 14px;
}
.mfp.mfp-project-intake-onboarding .mfp-form-title {
  font-size: clamp(22px, 4vw, 32px);
  font-weight: 800;
  line-height: 1.2;
  margin: 0 0 10px;
  color: #fff;
}
.mfp.mfp-project-intake-onboarding .mfp-form-subtitle {
  font-size: 15px;
  line-height: 1.6;
  color: rgba(255,255,255,0.85);
  margin: 0;
  max-width: 560px;
}

/* ---------- Stepper ---------- */
.mfp.mfp-project-intake-onboarding .mfp-stepper {
  background: var(--mf-surface, #ffffff);
  border-bottom: 1px solid var(--mf-border, #e2e8f0);
  padding: 0 48px;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
}
.mfp.mfp-project-intake-onboarding .mfp-stepper-list {
  display: flex;
  list-style: none;
  margin: 0;
  padding: 0;
  gap: 0;
  min-width: max-content;
}
.mfp.mfp-project-intake-onboarding .mfp-stepper-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 18px 24px 18px 0;
  position: relative;
  cursor: default;
  flex: 1;
  min-width: 120px;
}
.mfp.mfp-project-intake-onboarding .mfp-stepper-item + .mfp-stepper-item::before {
  content: '';
  position: absolute;
  left: -4px;
  top: 50%;
  transform: translateY(-50%);
  width: 16px;
  height: 1px;
  background: var(--mf-border, #e2e8f0);
}
.mfp.mfp-project-intake-onboarding .mfp-step-indicator {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: var(--mf-border, #e2e8f0);
  color: var(--mf-muted, #64748b);
  font-size: 13px;
  font-weight: 700;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  transition: background 0.2s, color 0.2s;
}
.mfp.mfp-project-intake-onboarding .mfp-stepper-item[data-step-state="active"] .mfp-step-indicator,
.mfp.mfp-project-intake-onboarding .mfp-stepper-item.active .mfp-step-indicator {
  background: var(--mf-primary, #0bb39b);
  color: #fff;
  box-shadow: 0 0 0 4px rgba(11,179,155,0.15);
}
.mfp.mfp-project-intake-onboarding .mfp-stepper-item[data-step-state="done"] .mfp-step-indicator,
.mfp.mfp-project-intake-onboarding .mfp-stepper-item.done .mfp-step-indicator {
  background: var(--mf-accent, #0bb39b);
  color: #fff;
}
.mfp.mfp-project-intake-onboarding .mfp-step-info {
  display: flex;
  flex-direction: column;
  gap: 1px;
}
.mfp.mfp-project-intake-onboarding .step-label {
  font-size: 13px;
  font-weight: 700;
  color: var(--mf-text, #1a1a2e);
  white-space: nowrap;
}
.mfp.mfp-project-intake-onboarding .step-subtitle {
  font-size: 11px;
  color: var(--mf-muted, #64748b);
  white-space: nowrap;
}

/* ---------- Page / Step body ---------- */
.mfp.mfp-project-intake-onboarding .mfp-page {
  background: var(--mf-surface, #ffffff);
  padding: 40px 48px;
  display: flex;
  flex-direction: column;
  gap: 24px;
}

/* ---------- Step intro block ---------- */
.mfp.mfp-project-intake-onboarding .mfp-step-intro {
  border-left: 3px solid var(--mf-primary, #0bb39b);
  padding-left: 16px;
}
.mfp.mfp-project-intake-onboarding .step-title {
  font-size: clamp(18px, 3vw, 22px);
  font-weight: 800;
  margin: 0 0 6px;
  color: var(--mf-text, #1a1a2e);
}
.mfp.mfp-project-intake-onboarding .step-intro {
  font-size: 14px;
  line-height: 1.6;
  color: var(--mf-muted, #64748b);
  margin: 0;
}

/* ---------- Field wrapper ---------- */
.mfp.mfp-project-intake-onboarding .mfp-field-wrap {
  display: flex;
  flex-direction: column;
  gap: 4px;
  width: 100%;
}

/* ---------- Two-column grid ---------- */
.mfp.mfp-project-intake-onboarding .mfp-fields-grid {
  display: grid;
  gap: 16px;
  width: 100%;
}
.mfp.mfp-project-intake-onboarding .mfp-grid-2 {
  grid-template-columns: repeat(2, 1fr);
}

/* ---------- Native input / select / textarea styling ---------- */
.mfp.mfp-project-intake-onboarding input[type="text"],
.mfp.mfp-project-intake-onboarding input[type="email"],
.mfp.mfp-project-intake-onboarding input[type="tel"],
.mfp.mfp-project-intake-onboarding input[type="number"],
.mfp.mfp-project-intake-onboarding input[type="date"],
.mfp.mfp-project-intake-onboarding select,
.mfp.mfp-project-intake-onboarding textarea {
  width: 100%;
  padding: 11px 14px;
  font-size: 14px;
  line-height: 1.5;
  font-family: inherit;
  color: var(--mf-text, #1a1a2e);
  background: var(--mf-bg, #f8fafc);
  border: 1.5px solid var(--mf-border, #e2e8f0);
  border-radius: var(--mf-radius, 8px);
  transition: border-color 0.18s, box-shadow 0.18s;
  -webkit-appearance: none;
  appearance: none;
  outline: none;
}
.mfp.mfp-project-intake-onboarding input:focus,
.mfp.mfp-project-intake-onboarding select:focus,
.mfp.mfp-project-intake-onboarding textarea:focus {
  border-color: var(--mf-primary, #0bb39b);
  box-shadow: 0 0 0 3px rgba(11,179,155,0.12);
  background: var(--mf-surface, #ffffff);
}
.mfp.mfp-project-intake-onboarding textarea {
  resize: vertical;
  min-height: 110px;
}

/* ---------- Labels ---------- */
.mfp.mfp-project-intake-onboarding label {
  font-size: 13px;
  font-weight: 600;
  color: var(--mf-text, #1a1a2e);
  letter-spacing: 0.01em;
}

/* ---------- Radio card group ---------- */
.mfp.mfp-project-intake-onboarding .mfp-radio-card-group .mf-radio-group,
.mfp.mfp-project-intake-onboarding .mfp-radio-card-group [class*="radio-list"] {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 10px;
}
.mfp.mfp-project-intake-onboarding .mfp-radio-card-group label {
  display: flex;
  align-items: center;
  gap: 8px;
  border: 1.5px solid var(--mf-border, #e2e8f0);
  border-radius: var(--mf-radius, 8px);
  padding: 10px 14px;
  cursor: pointer;
  font-weight: 500;
  transition: border-color 0.18s, background 0.18s;
}
.mfp.mfp-project-intake-onboarding .mfp-radio-card-group input[type="radio"]:checked + label,
.mfp.mfp-project-intake-onboarding .mfp-radio-card-group label:has(input[type="radio"]:checked) {
  border-color: var(--mf-primary, #0bb39b);
  background: rgba(11,179,155,0.06);
  color: var(--mf-primary, #0bb39b);
}

/* ---------- Inline checkbox ---------- */
.mfp.mfp-project-intake-onboarding .mfp-checkbox-inline,
.mfp.mfp-project-intake-onboarding .mfp-consent {
  justify-content: center;
}

/* ---------- File upload zone ---------- */
.mfp.mfp-project-intake-onboarding [class*="file-upload"],
.mfp.mfp-project-intake-onboarding [class*="mf-file"] {
  border: 2px dashed var(--mf-border, #e2e8f0);
  border-radius: var(--mf-radius, 8px);
  padding: 28px;
  text-align: center;
  transition: border-color 0.2s, background 0.2s;
}
.mfp.mfp-project-intake-onboarding [class*="file-upload"]:hover,
.mfp.mfp-project-intake-onboarding [class*="mf-file"]:hover {
  border-color: var(--mf-primary, #0bb39b);
  background: rgba(11,179,155,0.04);
}

/* ---------- Rating ---------- */
.mfp.mfp-project-intake-onboarding [class*="mf-rating"] svg,
.mfp.mfp-project-intake-onboarding [class*="rating"] svg {
  color: var(--mf-primary, #0bb39b);
}

/* ---------- Actions bar ---------- */
.mfp.mfp-project-intake-onboarding .mfp-actions {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 10px;
  padding: 20px 48px 36px;
  background: var(--mf-surface, #ffffff);
  border-top: 1px solid var(--mf-border, #e2e8f0);
}
.mfp.mfp-project-intake-onboarding .mfp-btn {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  font-size: 14px;
  font-weight: 700;
  padding: 11px 22px;
  border-radius: var(--mf-radius, 8px);
  border: none;
  cursor: pointer;
  transition: background 0.18s, box-shadow 0.18s, transform 0.12s;
  font-family: inherit;
  line-height: 1;
}
.mfp.mfp-project-intake-onboarding .mfp-btn:active {
  transform: translateY(1px);
}
.mfp.mfp-project-intake-onboarding .mfp-btn-back {
  background: transparent;
  color: var(--mf-muted, #64748b);
  border: 1.5px solid var(--mf-border, #e2e8f0);
  margin-right: auto;
}
.mfp.mfp-project-intake-onboarding .mfp-btn-back:hover {
  background: var(--mf-bg, #f8fafc);
  color: var(--mf-text, #1a1a2e);
}
.mfp.mfp-project-intake-onboarding .mfp-btn-next {
  background: var(--mf-primary, #0bb39b);
  color: #fff;
  box-shadow: 0 2px 12px rgba(11,179,155,0.28);
}
.mfp.mfp-project-intake-onboarding .mfp-btn-next:hover {
  background: var(--mf-accent, #09a08a);
  box-shadow: 0 4px 18px rgba(11,179,155,0.36);
}
.mfp.mfp-project-intake-onboarding .mfp-btn-submit {
  background: var(--mf-primary, #0bb39b);
  color: #fff;
  box-shadow: 0 2px 12px rgba(11,179,155,0.28);
  display: none;
}
.mfp.mfp-project-intake-onboarding .mfp-btn-submit.visible {
  display: inline-flex;
}
.mfp.mfp-project-intake-onboarding .mfp-btn-submit:hover {
  background: var(--mf-accent, #09a08a);
}

/* ---------- Responsive ---------- */
@media (max-width: 680px) {
  .mfp.mfp-project-intake-onboarding .mfp-header {
    padding: 28px 24px 22px;
  }
  .mfp.mfp-project-intake-onboarding .mfp-stepper {
    padding: 0 16px;
  }
  .mfp.mfp-project-intake-onboarding .mfp-stepper-item {
    min-width: 90px;
    padding: 14px 16px 14px 0;
  }
  .mfp.mfp-project-intake-onboarding .mfp-page {
    padding: 28px 24px;
    gap: 18px;
  }
  .mfp.mfp-project-intake-onboarding .mfp-grid-2 {
    grid-template-columns: 1fr;
  }
  .mfp.mfp-project-intake-onboarding .mfp-radio-card-group .mf-radio-group,
  .mfp.mfp-project-intake-onboarding .mfp-radio-card-group [class*="radio-list"] {
    grid-template-columns: 1fr 1fr;
  }
  .mfp.mfp-project-intake-onboarding .mfp-actions {
    padding: 16px 24px 28px;
    flex-wrap: wrap;
  }
  .mfp.mfp-project-intake-onboarding .mfp-btn-back {
    order: 2;
  }
  .mfp.mfp-project-intake-onboarding .mfp-btn-next,
  .mfp.mfp-project-intake-onboarding .mfp-btn-submit {
    flex: 1;
    justify-content: center;
  }
}
@media (max-width: 400px) {
  .mfp.mfp-project-intake-onboarding .mfp-radio-card-group .mf-radio-group,
  .mfp.mfp-project-intake-onboarding .mfp-radio-card-group [class*="radio-list"] {
    grid-template-columns: 1fr;
  }
  .mfp.mfp-project-intake-onboarding .mfp-step-info {
    display: none;
  }
}

