.mfp.mfp-project-intake-onboarding.mfp-native-generated .step-subtitle{overflow:hidden!important;text-overflow:ellipsis!important;max-width:100%!important;}
/* --- MOBILE <=640px: collapse to a compact dot stepper (mirrors the mock,
   which HIDES its per-step rail below md and shows only a "Step N of M"
   cue). Here: keep the numbered circles in one centered non-scrolling row,
   hide every label/substep, and reveal ONLY the active step's label. --- */
@media (max-width:640px){
  .mfp.mfp-project-intake-onboarding.mfp-native-generated .mfp-stepper{height:auto!important;min-height:0!important;padding:12px 16px!important;overflow:hidden!important;}
  .mfp.mfp-project-intake-onboarding.mfp-native-generated .mfp-stepper-list{width:100%!important;min-width:0!important;height:auto!important;gap:6px!important;justify-content:center!important;align-items:center!important;flex-wrap:nowrap!important;}
  .mfp.mfp-project-intake-onboarding.mfp-native-generated .mfp-stepper-item{flex:0 0 auto!important;min-width:0!important;height:auto!important;min-height:0!important;margin:0!important;padding:0!important;gap:6px!important;align-items:center!important;}
  /* connector: switch from absolute overlay to an in-flow 12px bar between dots */
  .mfp.mfp-project-intake-onboarding.mfp-native-generated .mfp-stepper-item + .mfp-stepper-item::before{position:static!important;transform:none!important;left:auto!important;top:auto!important;width:12px!important;height:2px!important;flex:0 0 12px!important;margin:0!important;}
  .mfp.mfp-project-intake-onboarding.mfp-native-generated .mfp-step-indicator{width:28px!important;height:28px!important;font-size:12px!important;}
  /* hide all labels/substeps by default */
  .mfp.mfp-project-intake-onboarding.mfp-native-generated .mfp-step-info{display:none!important;}
  .mfp.mfp-project-intake-onboarding.mfp-native-generated .step-subtitle{display:none!important;}
  /* ...reveal only the ACTIVE step's label as the single "you are here" cue */
  .mfp.mfp-project-intake-onboarding.mfp-native-generated .mfp-stepper-item.is-active .mfp-step-info{display:flex!important;}
  .mfp.mfp-project-intake-onboarding.mfp-native-generated .mfp-stepper-item.is-active .step-label{display:block!important;font-size:13px!important;font-weight:700!important;white-space:nowrap!important;color:var(--mf-text,#1a1a2e)!important;}
}
